# GENERATED BY GEMINI 3.1

import numpy as np

def make_mobius_strip(n_samples=2000, radius=1.0, width=1.0, noise=0.05, random_state=None):
    """
    Generates a 3D Möbius strip dataset.
    
    Parameters:
    - n_samples: Number of data points to generate.
    - radius: The base radius of the main loop.
    - width: The width of the strip.
    - noise: Standard deviation of Gaussian noise added to the points.
    - random_state: Seed for reproducibility.
    
    Returns:
    - X: Array of shape (n_samples, 3) containing the 3D coordinates.
    - u: Array of shape (n_samples,) containing the angle parameter 
         (useful for coloring plots to track the manifold).
    """
    if random_state is not None:
        np.random.seed(random_state)

    # u: angle around the loop [0, 2pi]
    u = np.random.uniform(0, 2 * np.pi, n_samples)
    
    # v: position across the width of the strip [-1, 1]
    v = np.random.uniform(-1, 1, n_samples) * width

    # Calculate the varying radius due to the twist
    R = radius + (v / 2.0) * np.cos(u / 2.0)

    # Calculate 3D coordinates
    x = R * np.cos(u)
    y = R * np.sin(u)
    z = (v / 2.0) * np.sin(u / 2.0)

    # Stack into a (N, 3) matrix
    X = np.c_[x, y, z]

    # Add Gaussian noise
    if noise > 0.0:
        X += np.random.normal(0, noise, X.shape)

    return X, u